import { useState, useEffect } from 'react';
import { Spinner, Modal, Btn, Badge, useToast } from '../../components/shared/index.jsx';
import { getJobs, getJobSubmissions } from '../../api/index.js';

export function HRCVRankingPage() {
  const toast = useToast();

  const [jobs, setJobs]           = useState([]);
  const [selectedJob, setSelectedJob] = useState(null);
  const [rankings, setRankings]   = useState([]);
  const [loading, setLoading]     = useState(false);
  const [rankingLoading, setRankingLoading] = useState(false);

  useEffect(() => {
    loadJobs();
  }, []);

  const loadJobs = async () => {
    setLoading(true);
    try {
      const data = await getJobs();
      setJobs(data);
    } catch (err) {
      toast('Failed to load jobs', 'error');
    }
    setLoading(false);
  };

  const handleRankCVs = async () => {
    if (!selectedJob) {
      toast('Please select a job', 'error');
      return;
    }
    setRankingLoading(true);
    try {
      // Assuming we add getJobRanking to API
      const response = await fetch(`http://127.0.0.1:8000/api/recruitment/jobs/${selectedJob.id}/ranking/`, {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('access')}`,
        },
      });
      const data = await response.json();
      if (response.ok) {
        setRankings(data);
      } else {
        toast(data.detail || 'Failed to rank CVs', 'error');
      }
    } catch (err) {
      toast('Error ranking CVs', 'error');
    }
    setRankingLoading(false);
  };

  return (
    <div>
      <h1>CV Ranking</h1>
      <p>Rank CVs for job applications using AI-powered analysis.</p>

      {/* Job Selection */}
      <div style={{ marginBottom: 20 }}>
        <label>Select Job:</label>
        <select
          value={selectedJob?.id || ''}
          onChange={(e) => {
            const job = jobs.find(j => j.id == e.target.value);
            setSelectedJob(job);
            setRankings([]);
          }}
          style={{ marginLeft: 10, padding: 8 }}
        >
          <option value="">Choose a job...</option>
          {jobs.map(job => (
            <option key={job.id} value={job.id}>{job.title}</option>
          ))}
        </select>
      </div>

      {/* Rank Button */}
      <Btn onClick={handleRankCVs} disabled={rankingLoading || !selectedJob}>
        {rankingLoading ? 'Ranking...' : 'Rank CVs'}
      </Btn>

      {/* Rankings Table */}
      {rankings.length > 0 && (
        <div style={{ marginTop: 20 }}>
          <h2>Ranked Candidates</h2>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ background: '#f0f0f0' }}>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Rank</th>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Candidate</th>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Final Score</th>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Similarity</th>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Skill Match</th>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Matched Skills</th>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Evidence</th>
              </tr>
            </thead>
            <tbody>
              {rankings.map((rank, index) => (
                <tr key={rank.submission_id}>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>{index + 1}</td>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>{rank.candidate_name}</td>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>{rank.final_score}%</td>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>{rank.similarity_score}%</td>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>{rank.skill_match_pct}%</td>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>{rank.matched_skills.join(', ') || 'None'}</td>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>{rank.evidence.join(' | ') || 'None'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {loading && <Spinner />}
    </div>
  );
}
